ps.pstext:
if !IsFeatureImplemented(FEAT_SVE2) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 8;
let dst : integer = UInt(Zd);
let s1 : integer = UInt(Zn);
let s2 : integer = (s1 + 1) MOD 32;
let position : integer{} = UInt(imm8h::imm8l) * 8;

if !IsFeatureImplemented(FEAT_SVE) && !IsFeatureImplemented(FEAT_SME) then
    EndOfDecode(Decode_UNDEF);
end;
let esize : integer{} = 8;
let dst : integer = UInt(Zdn);
let s1 : integer = dst;
let s2 : integer = UInt(Zm);
let position : integer{} = UInt(imm8h::imm8l) * 8;

CheckSVEEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV esize;
let operand1 : bits(VL) = Z{}(s1);
let operand2 : bits(VL) = Z{}(s2);
var result : bits(VL);

let concat : bits(VL*2) = operand2 :: operand1;

if position >= VL then
    result = concat[VL-1:0];
else
    result = concat[(position+VL)-1:position];
end;

Z{VL}(dst) = result;
